sql:
SELECT COUNT(*) AS total_homes_in_high_income_locations
FROM homes h
JOIN locations l ON h.location_id = l.location_id
WHERE l.average_income > (
    SELECT AVG(median_home_value) FROM locations
);

SELECT location_name, rank
FROM locations
ORDER BY rank DESC;

SELECT location_name, rank, population, average_income, median_home_value
FROM locations
ORDER BY population DESC;

SELECT SUM(number_of_homes) AS total_homes_count
FROM homes
WHERE location_id = 1;

SELECT l.location_name, l.median_home_value
FROM locations l
WHERE l.median_home_value > (
    SELECT AVG(median_home_value)
    FROM locations
);

SELECT location_id, COUNT(home_id) AS number_of_homes
FROM homes
GROUP BY location_id;

SELECT home_id, number_of_rooms, square_footage, condition
FROM homes
WHERE year_built BETWEEN 1980 AND 1989;

SELECT home_type_name, AVG(average_square_footage) AS avg_square_footage
FROM home_types
GROUP BY home_type_name;
